  await new Promise(r => ws.on('open', r));

  // Get iframe targets from CDP
  const targets = await new Promise((resolve, reject) => {
    const msgId = id++;
    ws.send(JSON.stringify({ id: msgId, method: 'Target.getTargets' }));
    const handler = (raw) => {
      const msg = JSON.parse(raw);
