  for (const iframe of iframes) {
    console.log('iframe:', iframe.url?.substring(0, 120), 'targetId:', iframe.targetId);
  }

  // Check the hsprotect iframe content
  const hsprotect = iframes.find(f => f.url?.includes('hsprotect'));
  if (hsprotect) {
    console.log('\n--- Attaching to hsprotect iframe ---');
    const session = await send('Target.attachToTarget', { targetId: hsprotect.targetId, flatten: true });
    const sessionId = session.result?.sessionId;
    console.log('Session:', sessionId);

    // Evaluate in iframe context
    const evalResult = await send('Runtime.evaluate', {
      expression: `document.body.innerHTML.substring(0, 2000)`,
      returnByValue: true
    });
    console.log('hsprotect content:', evalResult.result?.result?.value?.substring(0, 500));
  }

  ws.close();
}

main().catch(console.error);
