const WS_URL = 'ws://172.18.0.3:50219/devtools/page/5CA6D33FB8C496DE6C49B3266FFCF297';

async function main() {
  const ws = new WebSocket(WS_URL);
  let id = 1;

  const send = (method, params = {}) => new Promise((resolve, reject) => {
    const msgId = id++;
    const timeout = setTimeout(() => reject(new Error('timeout')), 15000);
    ws.send(JSON.stringify({ id: msgId, method, params }));
    const handler = (raw) => {
      const msg = JSON.parse(raw);
      if (msg.id === msgId) {
        clearTimeout(timeout);
        ws.removeListener('message', handler);
        resolve(msg);
      }
    };
    ws.on('message', handler);
  });

  await new Promise(r => ws.on('open', r));

  // Check for error messages, hidden elements, and CAPTCHA state
  const result = await send('Runtime.evaluate', {
    expression: `
      (function() {
        // Check for error messages
        const errors = document.querySelectorAll('[role="alert"], [class*="error"], [class*="Error"], .fui-Field__validationMessage');
        const errorTexts = Array.from(errors).map(e => e.textContent.trim()).filter(t => t);

        // Check for px-captcha
        const captcha = document.getElementById('px-captcha');
        const captchaInfo = captcha ? {
          exists: true,
          visible: captcha.offsetParent !== null || captcha.offsetWidth > 0,
          innerHTML: captcha.innerHTML.substring(0, 200),
          children: captcha.children.length
        } : { exists: false };

        // Check iframes
        const iframes = document.querySelectorAll('iframe');
        const iframeInfo = Array.from(iframes).map(f => ({
          src: (f.src || '').substring(0, 100),
          visible: f.offsetWidth > 0 && f.offsetHeight > 0,
          w: f.offsetWidth,
          h: f.offsetHeight
        }));

        // Check Next button state
        const nextBtn = Array.from(document.querySelectorAll('button')).find(b => b.textContent.trim() === 'Next');
        const nextInfo = nextBtn ? {
          disabled: nextBtn.disabled,
          ariaDisabled: nextBtn.getAttribute('aria-disabled'),
          loading: nextBtn.querySelector('[class*="spinner"]') !== null
        } : null;

        return JSON.stringify({
          errors: errorTexts,
          captcha: captchaInfo,
          iframes: iframeInfo,
          nextButton: nextInfo
        }, null, 2);
      })()
    `,
    returnByValue: true
  });

  console.log(result.result?.result?.value);

  ws.close();
}

