import WebSocket from '/tmp/node_modules/ws/index.js';

const WS_URL = 'ws://172.18.0.3:50219/devtools/page/5CA6D33FB8C496DE6C49B3266FFCF297';

async function main() {
  const ws = new WebSocket(WS_URL);
  let id = 1;

  const send = (method, params = {}) => new Promise((resolve, reject) => {
    const msgId = id++;
    const timeout = setTimeout(() => reject(new Error('timeout')), 15000);
    ws.send(JSON.stringify({ id: msgId, method, params }));
    const handler = (raw) => {
      const msg = JSON.parse(raw);
      if (msg.id === msgId) {
        clearTimeout(timeout);
        ws.removeListener('message', handler);
        resolve(msg);
      }
    };
    ws.on('message', handler);
  });

  await new Promise(r => ws.on('open', r));

  // Helper: get element center
  async function getElementCenter(selector) {
    const result = await send('Runtime.evaluate', {
      expression: `
        (function() {
          const el = document.querySelector('${selector}');
          if (!el) return null;
          const rect = el.getBoundingClientRect();
          return {x: rect.x + rect.width/2, y: rect.y + rect.height/2};
        })()
      `,
      returnByValue: true
    });
    return result.result?.result?.value;
  }

  // Helper: click at coordinates
  async function clickAt(x, y) {
    await send('Input.dispatchMouseEvent', { type: 'mousePressed', x, y, button: 'left', clickCount: 1 });
    await send('Input.dispatchMouseEvent', { type: 'mouseReleased', x, y, button: 'left', clickCount: 1 });
  }

  // Helper: type text
  async function typeText(text) {
    for (const char of text) {
      await send('Input.dispatchKeyEvent', { type: 'keyDown', text: char });
      await send('Input.dispatchKeyEvent', { type: 'keyUp', text: char });
      await new Promise(r => setTimeout(r, 50));
    }
  }

  // Step 1: Reset month dropdown by clicking it
  console.log('Clicking month dropdown...');
  const monthCenter = await getElementCenter('#BirthMonthDropdown');
  if (!monthCenter) { console.log('Month dropdown not found'); ws.close(); return; }
  await clickAt(monthCenter.x, monthCenter.y);
  await new Promise(r => setTimeout(r, 500));

  // Type "May" to filter
  console.log('Typing May...');
  await typeText('May');
  await new Promise(r => setTimeout(r, 500));

  // Press Enter to select
  console.log('Pressing Enter...');
  await send('Input.dispatchKeyEvent', { type: 'keyDown', key: 'Enter', code: 'Enter', windowsVirtualKeyCode: 13 });
  await send('Input.dispatchKeyEvent', { type: 'keyUp', key: 'Enter', code: 'Enter', windowsVirtualKeyCode: 13 });
  await new Promise(r => setTimeout(r, 500));

  // Step 2: Reset day dropdown
  console.log('Clicking day dropdown...');
  const dayCenter = await getElementCenter('#BirthDayDropdown');
  if (!dayCenter) { console.log('Day dropdown not found'); ws.close(); return; }
  await clickAt(dayCenter.x, dayCenter.y);
  await new Promise(r => setTimeout(r, 500));

  // Type "12"
  console.log('Typing 12...');
  await typeText('12');
  await new Promise(r => setTimeout(r, 500));

  // Press Enter
  console.log('Pressing Enter...');
  await send('Input.dispatchKeyEvent', { type: 'keyDown', key: 'Enter', code: 'Enter', windowsVirtualKeyCode: 13 });
  await send('Input.dispatchKeyEvent', { type: 'keyUp', key: 'Enter', code: 'Enter', windowsVirtualKeyCode: 13 });
  await new Promise(r => setTimeout(r, 500));

  // Verify
  const verify = await send('Runtime.evaluate', {
    expression: `
      (function() {
        const month = document.getElementById('BirthMonthDropdown');
        const day = document.getElementById('BirthDayDropdown');
        return JSON.stringify({
          month: {value: month?.value, text: month?.textContent?.trim()},
          day: {value: day?.value, text: day?.textContent?.trim()}
        });
      })()
    `,
    returnByValue: true
  });
  console.log('Values:', verify.result?.result?.value);

  // Check for errors
  const errors = await send('Runtime.evaluate', {
    expression: `
      (function() {
        const errs = document.querySelectorAll('[role="alert"], .fui-Field__validationMessage');
        return Array.from(errs).map(e => e.textContent.trim()).filter(t => t);
      })()
    `,
    returnByValue: true
  });
  console.log('Errors:', errors.result?.result?.value);

  ws.close();
}

main().catch(console.error);
