        // Check for hidden inputs
        const hiddenInputs = document.querySelectorAll('input[type="hidden"]');
        const hidden = Array.from(hiddenInputs).map(i => ({name: i.name, value: i.value}));

        // Check the form element itself
        const forms = document.querySelectorAll('form');
        const formInfo = Array.from(forms).map(f => ({action: f.action, method: f.method}));

        return JSON.stringify({formData, hiddenInputs: hidden, forms: formInfo}, null, 2);
      })()
    `,
    returnByValue: true
  });

  console.log(result.result?.result?.value);

  ws.close();
}

