    const timeout = setTimeout(() => reject(new Error('timeout')), 15000);
    ws.send(JSON.stringify({ id: msgId, method, params }));
    const handler = (raw) => {
      const msg = JSON.parse(raw);
      if (msg.id === msgId) {
        clearTimeout(timeout);
        ws.removeListener('message', handler);
        resolve(msg);
      }
    };
    ws.on('message', handler);
  });

  await new Promise(r => ws.on('open', r));

  // Set the birth year value using React-compatible method
  const result = await send('Runtime.evaluate', {
    expression: `
      (function() {
        const yearInput = document.querySelector('input[name="BirthYear"]');
        if (!yearInput) return 'BirthYear input not found';

        // Use native input setter to trigger React state update
        const nativeInputValueSetter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set;
        nativeInputValueSetter.call(yearInput, '1991');
        yearInput.dispatchEvent(new Event('input', { bubbles: true }));
        yearInput.dispatchEvent(new Event('change', { bubbles: true }));

        return 'Set year to: ' + yearInput.value;
      })()
    `,
    returnByValue: true
  });

  console.log(result.result?.result?.value);

  // Verify
  const verify = await send('Runtime.evaluate', {
    expression: `
      (function() {
        const yearInput = document.querySelector('input[name="BirthYear"]');
        return 'Year value: ' + yearInput.value;
      })()
    `,
    returnByValue: true
  });
  console.log(verify.result?.result?.value);

  // Now click Next
  const nextCenter = await send('Runtime.evaluate', {
    expression: `
      (function() {
        const btn = Array.from(document.querySelectorAll('button')).find(b => b.textContent.trim() === 'Next');
        const rect = btn.getBoundingClientRect();
        return {x: rect.x + rect.width/2, y: rect.y + rect.height/2};
      })()
    `,
    returnByValue: true
  });

  const coords = nextCenter.result?.result?.value;
  console.log('Clicking Next at:', coords);

  await send('Input.dispatchMouseEvent', { type: 'mousePressed', x: coords.x, y: coords.y, button: 'left', clickCount: 1 });
  await send('Input.dispatchMouseEvent', { type: 'mouseReleased', x: coords.x, y: coords.y, button: 'left', clickCount: 1 });

  // Wait for navigation
  await new Promise(r => setTimeout(r, 5000));

  // Check result
  const url = await send('Runtime.evaluate', {
    expression: 'window.location.href',
    returnByValue: true
  });
  console.log('URL:', url.result?.result?.value);

  const title = await send('Runtime.evaluate', {
    expression: 'document.title',
    returnByValue: true
  });
