import WebSocket from '/tmp/node_modules/ws/index.js';

const WS_URL = 'ws://172.18.0.3:50219/devtools/page/5CA6D33FB8C496DE6C49B3266FFCF297';

async function main() {
  const ws = new WebSocket(WS_URL);
  let id = 1;

  const sendRaw = (method, params = {}, sessionId = undefined) => new Promise((resolve, reject) => {
    const msgId = id++;
    const timeout = setTimeout(() => reject(new Error('timeout')), 15000);
    const msg = { id: msgId, method, params };
    if (sessionId) msg.sessionId = sessionId;
    ws.send(JSON.stringify(msg));
    const handler = (raw) => {
      const parsed = JSON.parse(raw);
      if (parsed.id === msgId) {
        clearTimeout(timeout);
        ws.removeListener('message', handler);
        resolve(parsed);
      }
    };
    ws.on('message', handler);
  });

  await new Promise(r => ws.on('open', r));

  // Find the FunCAPTCHA iframe
  const targets = await sendRaw('Target.getTargets');
  const iframes = targets.result?.targetInfos?.filter(t => t.type === 'iframe') || [];

  for (const iframe of iframes) {
    console.log('iframe:', iframe.url?.substring(0, 120));
  }

  // Look for funcaptcha iframe
  const funCaptcha = iframes.find(f => 
    f.url?.includes('funcaptcha') || f.url?.includes('arkoselabs') || 
    f.url?.includes('hcaptcha') || f.url?.includes('captcha')
  );

  if (!funCaptcha) {
    console.log('No FunCAPTCHA iframe found. Checking main page...');

    // Check main page for embedded captcha
    const mainResult = await sendRaw('Runtime.evaluate', {
      expression: `
        (function() {
          // Look for any iframe or div with captcha content
          const allIframes = document.querySelectorAll('iframe');
          const info = Array.from(allIframes).map(f => ({
            src: (f.src || '').substring(0, 150),
            visible: f.offsetWidth > 0,
            w: f.offsetWidth,
            h: f.offsetHeight,
            id: f.id
          }));

          // Also check for the arkose/fun captcha container
          const arkose = document.querySelector('[id*="arkose"], [class*="arkose"], [data-e2e*="arkose"]');

          return JSON.stringify({iframes: info, arkose: arkose?.outerHTML?.substring(0, 200)});
        })()
      `,
      returnByValue: true
    });
    console.log('Main page:', mainResult.result?.result?.value);
  } else {
    console.log('Found FunCAPTCHA iframe');

    // Attach to it
    const sess = await sendRaw('Target.attachToTarget', { targetId: funCaptcha.targetId, flatten: true });
    const sid = sess.result?.sessionId;

    // Get content
    const html = await sendRaw('Runtime.evaluate', {
      expression: 'document.body.innerHTML.substring(0, 2000)',
      returnByValue: true
    }, sid);
    console.log('HTML:', html.result?.result?.value?.substring(0, 1000));
  }

  ws.close();
}

main().catch(console.error);
